create type public.workflow_version_status as enum ('draft','under_review','approved','published','archived'); create type public.workflow_task_status as enum ('open','assigned','in_progress','blocked','pending_verification','completed','reopened','cancelled');
insert into public.permissions(key,name_ar,name_en) values ('workflows.view','عرض سير العمل','View workflows'),('workflows.start','بدء سير العمل','Start workflows'),('workflows.transition','تنفيذ انتقال','Transition workflows'),('workflows.assign','تعيين سير العمل','Assign workflows'),('workflows.reassign','إعادة تعيين','Reassign workflows'),('workflows.approve','اعتماد سير العمل','Approve workflows'),('workflows.reject','رفض سير العمل','Reject workflows'),('workflows.manage_definitions','إدارة التعريفات','Manage workflow definitions'),('workflows.publish','نشر سير العمل','Publish workflows'),('workflows.archive','أرشفة سير العمل','Archive workflows'),('workflows.manage_sla','إدارة SLA','Manage SLA'),('workflows.manage_escalations','إدارة التصعيد','Manage escalations'),('workflows.view_confidential_comments','عرض التعليقات السرية','View confidential comments'),('workflows.manage_tasks','إدارة المهام','Manage workflow tasks'),('workflows.verify_tasks','التحقق من المهام','Verify workflow tasks') on conflict(key) do nothing;
create table public.workflow_definitions(id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),module_key text not null,name_ar text,name_en text not null,description_ar text,description_en text,tags jsonb not null default '[]'::jsonb,owner_id uuid references public.user_profiles(id),status public.workflow_version_status not null default 'draft',current_version_id uuid,effective_date date,review_date date,created_at timestamptz not null default now(),created_by uuid references public.user_profiles(id),updated_at timestamptz not null default now(),updated_by uuid references public.user_profiles(id),archived_at timestamptz,archived_by uuid references public.user_profiles(id));
create table public.workflow_versions(id uuid primary key default gen_random_uuid(),definition_id uuid not null references public.workflow_definitions(id),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),version integer not null,status public.workflow_version_status not null default 'draft',definition jsonb not null default '{}'::jsonb,created_at timestamptz not null default now(),created_by uuid references public.user_profiles(id),updated_at timestamptz not null default now(),updated_by uuid references public.user_profiles(id),unique(definition_id,version)); alter table public.workflow_definitions add constraint workflow_current_version_fk foreign key(current_version_id) references public.workflow_versions(id) deferrable initially deferred;
create table public.workflow_instances(id uuid primary key default gen_random_uuid(),workflow_version_id uuid not null references public.workflow_versions(id),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),source_type text not null,source_id uuid not null,state_key text not null,locked boolean not null default false,revision integer not null default 1,assignee_id uuid references public.user_profiles(id),due_at timestamptz,created_at timestamptz not null default now(),created_by uuid references public.user_profiles(id),updated_at timestamptz not null default now(),updated_by uuid references public.user_profiles(id));
create table public.workflow_events(id uuid primary key default gen_random_uuid(),instance_id uuid not null references public.workflow_instances(id),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),kind text not null,action text not null,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now(),created_by uuid references public.user_profiles(id));
create table public.workflow_tasks(id uuid primary key default gen_random_uuid(),instance_id uuid not null references public.workflow_instances(id),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),title_ar text,title_en text not null,description text,assignee_id uuid references public.user_profiles(id),due_at timestamptz,priority text not null default 'medium',status public.workflow_task_status not null default 'open',completion_notes text,verified_by uuid references public.user_profiles(id),created_at timestamptz not null default now(),created_by uuid references public.user_profiles(id),updated_at timestamptz not null default now(),updated_by uuid references public.user_profiles(id));
create table public.workflow_approvals(id uuid primary key default gen_random_uuid(),instance_id uuid not null references public.workflow_instances(id),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),sequence integer not null,mode text not null,approver_id uuid references public.user_profiles(id),required_role text,status text not null default 'requested',distinct_from_id uuid references public.user_profiles(id),comment text,due_at timestamptz,created_at timestamptz not null default now(),created_by uuid references public.user_profiles(id));
create table public.workflow_comments(id uuid primary key default gen_random_uuid(),instance_id uuid not null references public.workflow_instances(id),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),body text not null,visibility text not null check(visibility in ('team','confidential')),created_at timestamptz not null default now(),created_by uuid not null references public.user_profiles(id)); create table public.workflow_reminders(id uuid primary key default gen_random_uuid(),instance_id uuid not null references public.workflow_instances(id),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),channel text not null,kind text not null,minimum_interval_minutes integer not null check(minimum_interval_minutes>=5),last_sent_at timestamptz,created_at timestamptz not null default now(),created_by uuid references public.user_profiles(id));
alter table public.workflow_definitions enable row level security; alter table public.workflow_versions enable row level security; alter table public.workflow_instances enable row level security; alter table public.workflow_events enable row level security; alter table public.workflow_tasks enable row level security; alter table public.workflow_approvals enable row level security; alter table public.workflow_comments enable row level security; alter table public.workflow_reminders enable row level security;
create or replace function public.can_workflow(permission_key text,t uuid,o uuid,f uuid) returns boolean language sql stable security definer set search_path=public as $$ select auth.uid() is not null and public.scope_allowed(t,o,f) and (public.has_platform_permission(permission_key,t,o,f) or public.has_platform_permission('platform.full_access',t,o,f)); $$;
create policy workflow_instance_read on public.workflow_instances for select using(public.can_workflow('workflows.view',tenant_id,organization_id,facility_id)); create policy workflow_events_read on public.workflow_events for select using(public.can_workflow('workflows.view',tenant_id,organization_id,facility_id)); create policy workflow_comments_read on public.workflow_comments for select using(public.can_workflow('workflows.view',tenant_id,organization_id,facility_id) and (visibility='team' or public.can_workflow('workflows.view_confidential_comments',tenant_id,organization_id,facility_id)));
create or replace function public.prevent_published_workflow_mutation() returns trigger language plpgsql security definer set search_path=public as $$ begin if old.status='published' then raise exception 'Published workflow versions are immutable'; end if; return new; end $$; create trigger workflow_versions_immutable before update or delete on public.workflow_versions for each row execute function public.prevent_published_workflow_mutation();
revoke all on function public.can_workflow(text,uuid,uuid,uuid) from public,anon; grant execute on function public.can_workflow(text,uuid,uuid,uuid) to authenticated; revoke all on function public.prevent_published_workflow_mutation() from public,anon,authenticated;
